import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.view.View;
import android.widget.ImageView;
import android.widget.ProgressBar;

import androidx.appcompat.app.AppCompatActivity;

public class DocumentViewerActivity extends AppCompatActivity {

    private static final String TAG = "DocumentViewerActivity";
    public static final int REQUEST_CODE_OPEN_DOCUMENT = 1001;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_document_viewer);

        if (getIntent().getData() != null) {
            Uri fileUri = getIntent().getData();
            displayDocument(fileUri);
        }
    }

    private void displayDocument(Uri fileUri) {
        ProgressBar progressBar = findViewById(R.id.progress_bar);
        ImageView imageView = findViewById(R.id.image_view);

        // Display the document
        if (fileUri.toString().endsWith(".pdf")) {
            // Show PDF viewer here
            PdfViewer pdfViewer = new PdfViewer(this, fileUri);
            setContentView(pdfViewer);
        } else if (fileUri.toString().endsWith(".jpg") || fileUri.toString().endsWith(".jpeg") ||
                fileUri.toString().endsWith(".png") || fileUri.toString().endsWith(".bmp")) {
            // Show image viewer here
            ImageView imageView = findViewById(R.id.image_view);
            imageView.setImageURI(fileUri);
        } else {
            Toast.makeText(this, "Unsupported file type", Toast.LENGTH_SHORT).show();
        }
    }

    @Override
    protected void onActivityResult(int requestCode, int resultCode, Intent data) {
        super.onActivityResult(requestCode, resultCode, data);

        if (requestCode == REQUEST_CODE_OPEN_DOCUMENT && resultCode == RESULT_OK) {
            Uri fileUri = data.getData();
            displayDocument(fileUri);
        }
    }

    public static class PdfViewer extends AppCompatActivity {

        private Uri pdfUri;

        public PdfViewer(Context context, Uri pdfUri) {
            this.pdfUri = pdfUri;
        }

        @Override
        protected void onCreate(Bundle savedInstanceState) {
            super.onCreate(savedInstanceState);

            // Show PDF viewer here
            setContentView(R.layout.activity_pdf_viewer);
            WebView webView = findViewById(R.id.web_view);
            webView.loadUrl("file://" + pdfUri.toString());
        }
    }
}